import{_ as s,H as n,f as p,i as e}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"日志保留与审计:为什么免费套餐常限制日志时间","description":"","frontmatter":{},"headers":[],"relativePath":"../cloudBasicsLearning/23-日志保留与审计.md","filePath":"../cloudBasicsLearning/23-日志保留与审计.md","lastUpdated":1779015580000}'),t={name:"../cloudBasicsLearning/23-日志保留与审计.md"};function l(i,a,o,c,d,r){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="日志保留与审计-为什么免费套餐常限制日志时间" tabindex="-1">日志保留与审计:为什么免费套餐常限制日志时间 <a class="header-anchor" href="#日志保留与审计-为什么免费套餐常限制日志时间" aria-label="Permalink to &quot;日志保留与审计:为什么免费套餐常限制日志时间&quot;">​</a></h1><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p><strong>日志保留是系统把请求、错误和操作记录保存多久;审计是用这些记录回答&quot;谁在什么时间做了什么&quot;</strong>。</p><p>日志最容易被误解成&quot;报错时看一眼控制台输出&quot;。对真实系统来说,日志不是临时调试信息,而是排障、追责、合规和安全分析的证据。用户说昨天晚上支付失败,你需要日志;后台数据被改了,你需要审计记录;某个 API 突然变慢,你需要请求日志和错误日志。</p><p>日志也不是越多越好。没有结构、没有检索、没有保留策略的日志,最后只是一堆昂贵的文本。小团队真正需要的是:关键事件能查到,敏感信息不乱存,免费套餐的保留时间心里有数。</p><h2 id="放在系统哪里" tabindex="-1">放在系统哪里 <a class="header-anchor" href="#放在系统哪里" aria-label="Permalink to &quot;放在系统哪里&quot;">​</a></h2><p>日志通常出现在这些位置:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>浏览器 / App</span></span>
<span class="line"><span>  -&gt; 前端错误、接口耗时、用户环境</span></span>
<span class="line"><span></span></span>
<span class="line"><span>CDN / 网关 / 反向代理</span></span>
<span class="line"><span>  -&gt; 请求来源、状态码、缓存命中、限流和 WAF 命中</span></span>
<span class="line"><span></span></span>
<span class="line"><span>应用服务</span></span>
<span class="line"><span>  -&gt; 业务请求、异常堆栈、定时任务、第三方 API 调用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>数据库和对象存储</span></span>
<span class="line"><span>  -&gt; 慢查询、连接错误、读写失败、权限访问</span></span>
<span class="line"><span></span></span>
<span class="line"><span>身份和管理后台</span></span>
<span class="line"><span>  -&gt; 登录、权限变更、密钥创建、删除资源、修改配置</span></span></code></pre></div><p>不同层的日志回答不同问题。CDN 日志能告诉你请求有没有到达边缘节点,但不一定知道业务为什么失败。应用日志知道订单创建失败的原因,但不一定知道前面是否被 WAF 拦截。审计日志则更关注管理动作,例如谁删除了数据库表、谁创建了新的 API Key、谁把存储桶改成公开访问。</p><p>排障时经常需要把几层日志串起来:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户反馈&quot;上传失败&quot;</span></span>
<span class="line"><span>  -&gt; 前端日志:按钮点击后接口返回 413</span></span>
<span class="line"><span>  -&gt; 网关日志:请求体超过限制</span></span>
<span class="line"><span>  -&gt; 应用日志:没有进入业务代码</span></span>
<span class="line"><span>  -&gt; 结论:不是代码 bug,是上传大小超过网关或平台限制</span></span></code></pre></div><h2 id="常见套餐和使用限制" tabindex="-1">常见套餐和使用限制 <a class="header-anchor" href="#常见套餐和使用限制" aria-label="Permalink to &quot;常见套餐和使用限制&quot;">​</a></h2><p>免费套餐最常见的限制就是日志保留时间。很多平台会让你实时查看日志,但只保留很短时间,可能是几小时、1 天、3 天或 7 天。超过这个窗口后,日志会被删除或只能在付费计划里查询。</p><p>这对小团队影响很大:</p><ul><li>用户周五晚上遇到问题,周一再查时日志可能已经没了.</li><li>安全事件发生后,你可能无法确认攻击从什么时候开始.</li><li>免费数据库或 Serverless 平台的日志只展示最近部分请求,无法做完整趋势分析.</li><li>审计日志可能是高级套餐能力,免费计划只能看到少量账号活动.</li></ul><p>除了保留时间,还要注意这些限制:</p><ul><li>日志量限制:每天能写入多少 MB 或多少条.</li><li>查询限制:只能按时间看,不能复杂检索或聚合.</li><li>导出限制:免费计划可能不能自动导出到对象存储.</li><li>字段限制:某些平台默认脱敏或不展示完整请求头、请求体.</li><li>团队权限限制:谁能看日志,谁能看审计记录,不一定能细分.</li></ul><p>日志也会产生成本。应用突然进入错误循环时,每秒打印大量错误,可能很快打爆日志写入额度。更糟的是,如果日志里包含密码、Token、身份证号、银行卡号等敏感信息,保留得越久风险越大。日志保留不是&quot;越久越专业&quot;,而是要在排障价值、合规要求、隐私风险和成本之间取平衡。</p><h2 id="小团队建议" tabindex="-1">小团队建议 <a class="header-anchor" href="#小团队建议" aria-label="Permalink to &quot;小团队建议&quot;">​</a></h2><p>独立开发和小团队可以先采用三层策略:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实时排障日志</span></span>
<span class="line"><span>  -&gt; 使用平台默认日志,保留 1-7 天也可以接受</span></span>
<span class="line"><span></span></span>
<span class="line"><span>关键业务日志</span></span>
<span class="line"><span>  -&gt; 登录、支付、订单、权限变更、数据删除,至少保留 30-90 天</span></span>
<span class="line"><span></span></span>
<span class="line"><span>审计日志</span></span>
<span class="line"><span>  -&gt; 管理员操作、密钥变更、权限变更、公开访问配置,尽量长期保留</span></span></code></pre></div><p>如果免费套餐日志保留很短,不要假设&quot;以后需要时再查&quot;。关键业务事件应该主动写入数据库表、审计表或低成本对象存储。比如支付回调、退款、用户权限变更,不能只依赖云平台的临时函数日志。</p><p>日志内容要结构化。不要只写:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>payment failed</span></span></code></pre></div><p>更好的方式是记录:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>event=payment_failed order_id=... provider=... reason=... request_id=...</span></span></code></pre></div><p>这样你才能按订单号、用户、请求 ID 串起前端、后端和第三方服务。注意不要把完整密码、完整 Token、完整身份证号写进日志。需要定位问题时,可以记录脱敏后的后四位、哈希值或内部 ID。</p><p>最低限度要做三件事:</p><ul><li>确认每个云服务免费套餐的日志保留时间.</li><li>把支付、权限、删除、密钥变更这类事件单独保存.</li><li>给日志量设置告警,避免错误循环变成账单问题.</li></ul><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p><strong>日志保留决定你事后还能不能还原现场,审计决定你能不能回答关键操作是谁做的;免费套餐日志短,关键证据就不能只放在平台控制台里</strong>。</p>`,31)])])}const g=s(t,[["render",l]]);export{u as __pageData,g as default};
